rule.specification:
案例代码: module fd32( input wire [31:0] d_1, input wire ce, input wire clk, output reg [31:0] q_1 );
initial //RTL级代码中不应使用initial结构，应采用复位的方式进行初始化 begin ... end
always@(posedge clk) begin ... end endmodule

  案例代码：
  ...
reg [1:0]current_state;
reg [1:0] next_state;
//parameter STATE_0=2'b00,STATE_1=2'b01, STATE_2=2'b10;


always @( current_state)
	begin
		case(current_state)
			2'b00: result <= 1'b0;
			2'b01: result  <= 1'b1;
			default: result  <= 1'b0;
		endcase
	end

always @(posedge clk or negedge rst)
	begin
		if(rst==1'b0)
			current_state <= 2'b00;
		else
			current_state  <= next_state;
	end

always @ (current_state or condition)
	begin
		case(current_state)
			2'b00: //违反
				begin
					if(condition)
						next_state = 2'b01;
					else
						next_state =2'b00;
				end
			2'b01:
				begin
					if(condition)
						next_state =2'b10;
					else
						next_state =2'b01;
				end

			...

		endcase
	end

  ...

案例代码：

  ...
	reg [1:0]current_state;
	reg [1:0] next_state;
	parameter STATE_0=2'b00,STATE_1=2'b01, STATE_2=2'b10,STATE_3=2'b11;

	...

	always @(posedge clk )//状态机在上电时应进入明确的初始状态
		begin

			current_state  <= next_state;

		end

	always @ (current_state or condition)
		begin
			case(current_state)
				STATE_0:
					begin
						if(condition)
							next_state = STATE_1;
						else
							next_state =STATE_0;
					end
				STATE_1:
					begin
						if(condition)
							next_state =STATE_0;
						else
							next_state =STATE_1;
					end

					...

			endcase  
		end

  ...

案例代码: module fd32( input wire d_1, input wire d_2, input wire clk, output reg q_1 ); wire rst_n;
assign rst_n=d_1 &d_2;
always@(posedge clk or negedge rst_n) begin if(rst_n == 1'b0) //不宜使用内部产生的信号作为复位信号 begin ... end else ... end endmodule

案例代码：
always@(state)
  begin
	case(state)//违反
		2’b00: z_out <=1’b1;
		2’b01: z_out <=1’b0;
		2’b10:
			begin
				z_out <=1’b1;
				s_out<=1’b1;
			end
	endcase
  end

案例代码：
module test (VCC, test_en, out);
  input VCC,test_en; 
  output out;  //示例中输入端口命名为“VCC”，输出端口命名为“out”，违反了基本命名规则
  ......
endmodule
